const express = require('express');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');
const cors = require('cors');

const app = express();

// --- Security middleware ---

// Set secure HTTP headers (XSS protection, no-sniff, HSTS, etc.)
app.use(helmet());

// CORS: restrict to known origins in production
app.use(cors({
  origin: process.env.ALLOWED_ORIGINS
    ? process.env.ALLOWED_ORIGINS.split(',')
    : '*',
}));

// Parse JSON bodies with a size limit to mitigate large-payload DoS
app.use(express.json({ limit: '1mb' }));
app.use(express.urlencoded({ extended: false, limit: '1mb' }));

// Rate limiting: 100 requests per 15 minutes per IP
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 100,
  standardHeaders: true,
  legacyHeaders: false,
  message: { error: 'Too many requests, please try again later.' },
});
app.use(limiter);

// Disable X-Powered-By header (also covered by helmet, but explicit is good)
app.disable('x-powered-by');

// --- Routes ---

app.get('/health', (_req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

app.get('/users', (req, res) => {
  // Validate optional query parameters
  const { id, name } = req.query;

  if (id !== undefined && (!/^\d+$/.test(id) || Number(id) < 1)) {
    return res.status(400).json({ error: 'Invalid id parameter. Must be a positive integer.' });
  }

  if (name !== undefined && (typeof name !== 'string' || name.length > 100)) {
    return res.status(400).json({ error: 'Invalid name parameter. Must be a string under 100 characters.' });
  }

  const users = [
    { id: 1, name: 'Alice', email: 'alice@example.com' },
    { id: 2, name: 'Bob', email: 'bob@example.com' },
  ];

  let results = users;
  if (id) {
    results = results.filter((u) => u.id === Number(id));
  }
  if (name) {
    const sanitized = name.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
    results = results.filter((u) =>
      u.name.toLowerCase().includes(sanitized.toLowerCase())
    );
  }

  res.json(results);
});

// --- 404 handler ---
app.use((_req, res) => {
  res.status(404).json({ error: 'Not found' });
});

// --- Global error handler ---
// Catches thrown errors and async rejections so stack traces are never leaked
// eslint-disable-next-line no-unused-vars
app.use((err, _req, res, _next) => {
  console.error('Unhandled error:', err.message);
  res.status(err.status || 500).json({
    error: process.env.NODE_ENV === 'production'
      ? 'Internal server error'
      : err.message,
  });
});

// --- Server start ---
const PORT = parseInt(process.env.PORT, 10) || 3000;
app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

module.exports = app;

