  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100,                  // limit each IP to 100 requests per window
  standardHeaders: true,
  legacyHeaders: false,
});
app.use(limiter);

// --- Disable fingerprinting ---
app.disable('x-powered-by');  // helmet does this too, but being explicit

// --- Routes ---
