const express = require('express');
const helmet = require('helmet');

const app = express();

// --- Security middleware ---
app.use(helmet());                           // Sets secure HTTP headers
app.use(express.json({ limit: '10kb' }));    // Parse JSON bodies with size limit
app.use(express.urlencoded({ extended: false, limit: '10kb' }));

// --- Disable fingerprinting ---
app.disable('x-powered-by');

// --- Routes ---
app.get('/health', (_req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

app.get('/users', (req, res) => {
  // Validate query parameters if accepting filters
  const allowedParams = ['id', 'name'];
  const unexpectedParams = Object.keys(req.query).filter(
    (key) => !allowedParams.includes(key)
  );

  if (unexpectedParams.length > 0) {
    return res.status(400).json({
      error: 'Bad Request',
      message: `Unexpected query parameters: ${unexpectedParams.join(', ')}`,
    });
  }

  const users = [
    { id: 1, name: 'Alice', email: 'alice@example.com' },
    { id: 2, name: 'Bob', email: 'bob@example.com' },
  ];

  // Optional: filter by id with validation
  if (req.query.id !== undefined) {
    const id = Number(req.query.id);
    if (!Number.isInteger(id) || id <= 0) {
      return res.status(400).json({
        error: 'Bad Request',
        message: 'Parameter "id" must be a positive integer.',
      });
    }
    const user = users.find((u) => u.id === id);
    if (!user) {
      return res.status(404).json({ error: 'Not Found' });
    }
    return res.json(user);
  }

  res.json(users);
});

// --- 404 handler (unknown routes) ---
app.use((_req, res) => {
  res.status(404).json({ error: 'Not Found' });
});

// --- Global error handler ---
// Must have 4 parameters for Express to recognize it as an error handler
app.use((err, _req, res, _next) => {
  console.error('Unhandled error:', err.message);
  res.status(err.status || 500).json({
    error: 'Internal Server Error',
    // Never leak stack traces or internal details to the client
    ...(process.env.NODE_ENV === 'development' && { detail: err.message }),
  });
});

// --- Server startup ---
const PORT = parseInt(process.env.PORT, 10) || 3000;
app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

module.exports = app;
```

