const express = require('express');
const helmet = require('helmet');         // Security headers
const rateLimit = require('express-rate-limit'); // Rate limiting
const morgan = require('morgan');         // Request logging

const app = express();

// --- Security middleware ---
app.use(helmet());                        // Set secure HTTP headers
app.disable('x-powered-by');             // Don't leak framework info

// --- Body parsing with size limits ---
app.use(express.json({ limit: '1mb' }));
app.use(express.urlencoded({ extended: false, limit: '1mb' }));

// --- Rate limiting ---
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000,  // 15 minutes
  max: 100,                   // limit each IP to 100 requests per window
  standardHeaders: true,
  legacyHeaders: false,
  message: { error: 'Too many requests, please try again later.' },
});
app.use(limiter);

// --- Request logging ---
app.use(morgan('combined'));

// --- Routes ---
app.get('/health', (req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

app.get('/users', (req, res) => {
  // In production, never return emails unless the requester is authenticated
  res.json([
    { id: 1, name: 'Alice' },
    { id: 2, name: 'Bob' },
  ]);
});

// --- 404 handler (must come after all routes) ---
app.use((req, res) => {
  res.status(404).json({ error: 'Not found' });
});

// --- Global error handler (4 args required by Express) ---
app.use((err, req, res, next) => {
  console.error(err.stack);  // Log full error internally
  res.status(err.status || 500).json({
    error: process.env.NODE_ENV === 'production'
      ? 'Internal server error'   // Safe message for production
      : err.message,              // Detailed message for development
  });
});

// --- Configurable port ---
const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

module.exports = app;
```

---

